package machinery

import (
	"fmt"
	"strings"
	"testing"
	"time"
)

func TestReplaceYear(t *testing.T) {
	currentYear := fmt.Sprintf("%v", time.Now().Year())

	tests := []struct {
		name     string
		input    string
		expected string
	}{
		{
			name:     "YEAR placeholder should be replaced with current year",
			input:    "Copyright YEAR The Kubernetes Authors.",
			expected: "Copyright " + currentYear + " The Kubernetes Authors.",
		},
		{
			name:     "no YEAR placeholder should remain unchanged",
			input:    "Copyright 2024 The Kubernetes Authors.",
			expected: "Copyright 2024 The Kubernetes Authors.",
		},
		{
			name:     "multiple YEAR placeholders should all be replaced",
			input:    "Copyright YEAR, then YEAR again.",
			expected: "Copyright " + currentYear + ", then " + currentYear + " again.",
		},
		{
			name:     "empty string should remain empty",
			input:    "",
			expected: "",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := ReplaceYear(tt.input)
			if result != tt.expected {
				t.Errorf("ReplaceYear() = %q, want %q", result, tt.expected)
			}
		})
	}
}

// TestWithBoilerplateYEARSubstitution verifies that WithBoilerplate calls ReplaceYear
func TestWithBoilerplateYEARSubstitution(t *testing.T) {
	currentYear := fmt.Sprintf("%v", time.Now().Year())

	// Create a scaffold with the boilerplate containing YEAR
	boilerplateInput := "/*\nCopyright YEAR The Kubernetes Authors.\n*/\n"
	scaffold := NewScaffold(Filesystem{}, WithBoilerplate(boilerplateInput))

	// Verify the boilerplate has YEAR replaced with current year
	if !strings.Contains(scaffold.injector.boilerplate, currentYear) {
		t.Errorf("Expected boilerplate to contain %q, got: %q", currentYear, scaffold.injector.boilerplate)
	}

	if strings.Contains(scaffold.injector.boilerplate, "YEAR") {
		t.Errorf("Expected boilerplate to NOT contain YEAR, got: %q", scaffold.injector.boilerplate)
	}
}

