// WithBoilerplate provides the boilerplate to the Scaffold
func WithBoilerplate(boilerplate string) ScaffoldOption {
	return func(s *Scaffold) {
		s.injector.boilerplate = ReplaceYear(boilerplate)
	}
}

// ReplaceYear replaces the YEAR placeholder in the boilerplate with the current year,
// matching the behavior of gengo and controller-gen.
func ReplaceYear(boilerplate string) string {
	return strings.ReplaceAll(boilerplate, "YEAR", fmt.Sprintf("%v", time.Now().Year()))
}

// WithResource provides the resource to the Scaffold
func WithResource(res *resource.Resource) ScaffoldOption {
	return func(s *Scaffold) {
		s.injector.resource = res
	}
}

